package main

import (
    "database/sql"
    "encoding/json"
    "log"
    "net/http"
    "strconv"

    _ "github.com/lib/pq" // postgresql driver
)

type Order struct {
    ID     int     `json:"id"`
    Amount float64 `json:"amount"`
}

func main() {
    http.HandleFunc("/orders/", orderHandler)
    log.Fatal(http.ListenAndServe(":8080", nil))
}

func orderHandler(w http.ResponseWriter, r *http.Request) {
    user := r.Context().Value("user").(*User) // assuming User is defined elsewhere

    if !user.IsAuthenticated {
        http.Error(w, "Unauthorized", 401)
        return
    }

    orderIDStr := r.URL.Path[len("/orders/"):]
    orderID, err := strconv.Atoi(orderIDStr)
    if err != nil {
        http.Error(w, "Invalid Order ID", 400)
        return
    }

    db, err := sql.Open("postgres", "user=postgres password=passwd dbname=test sslmode=disable")
    if err != nil {
        log.Fatal(err)
    }
    defer db.Close()

    var order Order
    row := db.QueryRow("SELECT id, amount FROM orders WHERE id=$1", orderID)
    switch err = row.Scan(&order.ID, &order.Amount); err {
    case sql.ErrNoRows:
        http.Error(w, "Order not found", 404)
    case nil:
        w.Header().Set("Content-Type", "application/json")
        json.NewEncoder(w).Encode(order)
    default:
        log.Println(err)
        http.Error(w, "Internal server error", 500)
    }
}